-- Template 1: Pokemon Battle Assistant (from article - Agents as Tools pattern)
('pokemon-battle-orchestrator', 'Pokemon Battle Orchestrator (Agents as Tools)', 'From the article: An orchestrator agent that routes requests to specialized Pokemon agents. Demonstrates the Agents-as-Tools pattern with multiple domain specialists and system prompt routing.', 'agents-as-tools', NULL, 'intermediate', '["orchestrator", "routing", "agents-as-tools", "multi-domain", "pokemon"]', 'https://levelup.gitconnected.com/strands-agents-interesting-multi-agent-pattern-0c7f97088b6d', 'Itsuki (Medium)', FALSE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":220},"data":{"label":"User Query"}},{"id":"orchestrator_1","type":"orchestrator-agent","position":{"x":380,"y":180},"data":{"label":"Game Orchestrator","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are an assistant that routes requests to specialized agents:\\n- For pokemon battle advice → Use the pokemon_battle_assistant tool\\n- For FGO gameplay → Use the fgo_assistant tool\\n\\nAlways select the most appropriate tool based on the user query.","temperature":0.7,"maxTokens":4000,"retryEnabled":true,"retryMaxAttempts":3,"maxTurns":10}},{"id":"agent_pokemon","type":"agent","position":{"x":720,"y":80},"data":{"label":"Pokemon Battle Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You specialize in giving pokemon battle related advices. Cover type matchups, move selection, team composition, and competitive strategies.","temperature":0.7,"maxTokens":4000}},{"id":"agent_fgo","type":"agent","position":{"x":720,"y":320},"data":{"label":"FGO Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You specialize in giving FGO (Fate/Grand Order mobile game) related advices. Cover servant builds, team comps, and event strategies.","temperature":0.7,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":380,"y":420},"data":{"label":"Response"}}],"edges":[{"id":"e1","source":"input_1","target":"orchestrator_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"orchestrator_1","target":"agent_pokemon","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e3","source":"orchestrator_1","target":"agent_fgo","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e4","source":"orchestrator_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 2: Pokemon Swarm Team (from article - Static Swarm pattern)
('pokemon-swarm-team', 'Pokemon Swarm Team (Autonomous Handoff)', 'From the article: A swarm of Pokemon specialists that autonomously hand off tasks. Demonstrates shared context, handoff detection, and collaborative problem solving without central control.', 'swarm', NULL, 'intermediate', '["swarm", "handoff", "autonomous", "collaboration", "pokemon", "shared-context"]', 'https://levelup.gitconnected.com/strands-agents-interesting-multi-agent-pattern-0c7f97088b6d', 'Itsuki (Medium)', FALSE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":220},"data":{"label":"Pokemon Question"}},{"id":"swarm_1","type":"swarm","position":{"x":360,"y":180},"data":{"label":"Pokemon Expert Team","maxHandoffs":20,"maxIterations":20,"executionTimeout":900,"nodeTimeout":300,"repetitiveHandoffDetectionWindow":8,"repetitiveHandoffMinUniqueAgents":3}},{"id":"agent_helper","type":"agent","position":{"x":720,"y":60},"data":{"label":"Pokemon Helper","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are a pokemon specialist answering general questions on pokemons. Hand off to battle specialist for battle advice, info specialist for detailed stats, or web researcher for latest news.","temperature":0.7,"maxTokens":4000}},{"id":"agent_battle","type":"agent","position":{"x":720,"y":180},"data":{"label":"Battle Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are a pokemon battle specialist. Answer questions on type matchups, competitive strategies, move selection, and team building.","temperature":0.7,"maxTokens":4000}},{"id":"agent_info","type":"agent","position":{"x":720,"y":300},"data":{"label":"Info Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are knowledgeable in pokemon details such as types, abilities, base stats, evolution chains, and move pools.","temperature":0.7,"maxTokens":4000}},{"id":"agent_web","type":"agent","position":{"x":720,"y":420},"data":{"label":"Web Researcher","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You specialize in looking for pokemon related information over the web. Search for tournament results, meta changes, and community discussions.","temperature":0.7,"maxTokens":4000}},{"id":"tool_http","type":"tool","position":{"x":960,"y":420},"data":{"label":"HTTP Request","toolType":"built-in","toolName":"http_request"}},{"id":"output_1","type":"output","position":{"x":360,"y":480},"data":{"label":"Expert Answer"}}],"edges":[{"id":"e1","source":"input_1","target":"swarm_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"swarm_1","target":"agent_helper","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e3","source":"swarm_1","target":"agent_battle","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e4","source":"swarm_1","target":"agent_info","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e5","source":"swarm_1","target":"agent_web","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e6","source":"tool_http","target":"agent_web","sourceHandle":"tool-output","targetHandle":"tools"},{"id":"e7","source":"swarm_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 3: Pokemon Research Graph (from article - Static Graph pattern)
('pokemon-research-graph', 'Pokemon Game Trend Report (Graph)', 'From the article: A structured graph where a helper agent feeds into parallel specialists (card game + video game), which converge into a reporter. Demonstrates parallel processing with aggregation.', 'graph', 'parallel', 'advanced', '["graph", "parallel", "aggregation", "report", "pokemon", "structured"]', 'https://levelup.gitconnected.com/strands-agents-interesting-multi-agent-pattern-0c7f97088b6d', 'Itsuki (Medium)', FALSE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":230},"data":{"label":"Research Topic"}},{"id":"agent_helper","type":"agent","position":{"x":340,"y":210},"data":{"label":"Pokemon Helper","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are a pokemon specialist answering questions on pokemons. Provide a comprehensive overview that the card game and video game specialists can expand upon.","temperature":0.7,"maxTokens":4000}},{"id":"agent_card","type":"agent","position":{"x":680,"y":100},"data":{"label":"Card Game Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are a pokemon card game (TCG) specialist. Analyze TCG trends, tournament meta, card values, and digital-physical integration like TCG Pocket.","temperature":0.7,"maxTokens":4000}},{"id":"agent_video","type":"agent","position":{"x":680,"y":340},"data":{"label":"Video Game Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are a pokemon video game specialist. Analyze game trends, competitive meta, open-world evolution, mobile strategy, and upcoming releases.","temperature":0.7,"maxTokens":4000}},{"id":"agent_reporter","type":"agent","position":{"x":1020,"y":220},"data":{"label":"Report Writer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-sonnet-4-20250514-v1:0","modelName":"Claude Sonnet 4","systemPrompt":"You are a report writing specialist. Summarize all information received from specialists into a comprehensive, well-structured trend report with executive summary, key findings, and future outlook.","temperature":0.5,"maxTokens":8000}},{"id":"output_1","type":"output","position":{"x":1320,"y":240},"data":{"label":"Trend Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_helper","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_helper","target":"agent_card","sourceHandle":"output","targetHandle":"user-input"},{"id":"e3","source":"agent_helper","target":"agent_video","sourceHandle":"output","targetHandle":"user-input"},{"id":"e4","source":"agent_card","target":"agent_reporter","sourceHandle":"output","targetHandle":"user-input"},{"id":"e5","source":"agent_video","target":"agent_reporter","sourceHandle":"output","targetHandle":"user-input"},{"id":"e6","source":"agent_reporter","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}'),

-- Template 4: Full-Featured Production Agent (all Strands features)
('production-agent-full', 'Production-Ready Agent (All Features)', 'Demonstrates ALL Strands SDK features: Bedrock Guardrails, OTEL tracing, Memory (Bedrock KB), Agent SOPs, retry strategy, conversation management, session persistence, structured output, streaming, and Human-in-the-Loop.', 'single-agent', NULL, 'advanced', '["production", "guardrails", "otel", "memory", "sop", "retry", "session", "structured-output", "full-featured"]', 'https://strandsagents.com/docs/user-guide/concepts/agents/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":200},"data":{"label":"User Request"}},{"id":"agent_1","type":"agent","position":{"x":380,"y":160},"data":{"label":"Production Agent","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a production-grade AI assistant with access to a knowledge base. Always verify facts before responding. Follow the SOP for structured workflows.","temperature":0.7,"maxTokens":4000,"streaming":true,"bedrockGuardrailEnabled":true,"bedrockGuardrailId":"your-guardrail-id","bedrockGuardrailVersion":"1","bedrockGuardrailTrace":true,"otelEnabled":true,"otelExporterType":"otlp_grpc","otelServiceName":"production-agent","otelSamplingRate":1.0,"memoryEnabled":true,"memoryType":"bedrock_kb","memoryKnowledgeBaseId":"your-kb-id","agentSopEnabled":true,"agentSopContent":"## Standard Operating Procedure\\n\\n### Step 1: Understand\\n- Parse user intent\\n- Identify required knowledge\\n\\n### Step 2: Research\\n- Query knowledge base\\n- Validate information\\n\\n### Step 3: Respond\\n- Format clearly\\n- Cite sources\\n- Ask for clarification if needed\\n\\n### Constraints\\n- Never expose PII\\n- Always cite sources","retryEnabled":true,"retryMaxAttempts":3,"retryInitialDelay":4,"retryMaxDelay":30,"conversationManager":"sliding_window","conversationWindowSize":20,"sessionManager":"file","maxTurns":15,"totalTokenBudget":100000,"humanInLoopEnabled":true,"humanInLoopMode":"high_risk","humanInLoopTimeout":300,"goalLoopEnabled":false}},{"id":"tool_retrieve","type":"tool","position":{"x":380,"y":20},"data":{"label":"Knowledge Base","toolType":"built-in","toolName":"retrieve"}},{"id":"tool_http","type":"tool","position":{"x":580,"y":20},"data":{"label":"HTTP Request","toolType":"built-in","toolName":"http_request"}},{"id":"output_1","type":"output","position":{"x":700,"y":200},"data":{"label":"Verified Response"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"tool_retrieve","target":"agent_1","sourceHandle":"tool-output","targetHandle":"tools"},{"id":"e3","source":"tool_http","target":"agent_1","sourceHandle":"tool-output","targetHandle":"tools"},{"id":"e4","source":"agent_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 5: Graph with Feedback Loop (from article - Cyclic Graph)
('graph-feedback-revision', 'Writer-Reviewer Feedback Loop (Cyclic Graph)', 'Demonstrates cyclic graphs with controlled iteration. A writer drafts content, a reviewer evaluates it, and the process loops until the reviewer approves. Uses max_node_executions to prevent infinite loops.', 'graph', 'feedback-loop', 'advanced', '["graph", "cyclic", "feedback-loop", "revision", "iterative", "quality-control"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/graph/#4-feedback-loop', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":200},"data":{"label":"Writing Task"}},{"id":"agent_writer","type":"agent","position":{"x":360,"y":180},"data":{"label":"Draft Writer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You write high-quality drafts. If you receive reviewer feedback, incorporate it into your revision. Aim for clarity, accuracy, and completeness.","temperature":0.8,"maxTokens":4000}},{"id":"agent_reviewer","type":"agent","position":{"x":700,"y":180},"data":{"label":"Quality Reviewer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You review drafts for quality. If the draft meets high standards, respond with APPROVED. Otherwise respond with REVISION NEEDED followed by specific, actionable feedback.","temperature":0.3,"maxTokens":2000}},{"id":"agent_publisher","type":"agent","position":{"x":1040,"y":180},"data":{"label":"Publisher","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You format and finalize approved content for publication. Add proper headings, formatting, and a brief summary.","temperature":0.5,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":1340,"y":200},"data":{"label":"Published Content"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_writer","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_writer","target":"agent_reviewer","sourceHandle":"output","targetHandle":"user-input"},{"id":"e3","source":"agent_reviewer","target":"agent_writer","sourceHandle":"output","targetHandle":"user-input"},{"id":"e4","source":"agent_reviewer","target":"agent_publisher","sourceHandle":"output","targetHandle":"user-input"},{"id":"e5","source":"agent_publisher","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}'),

-- Template 6: A2A Distributed ML Pipeline
('a2a-ml-pipeline', 'Distributed ML Pipeline (A2A + Graph)', 'Local data preparation with remote ML and NLP services via A2A protocol. Shows how to build distributed agent architectures where specialized processing runs on separate servers.', 'a2a', NULL, 'advanced', '["a2a", "distributed", "ml", "nlp", "remote", "microservices", "graph"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/agent-to-agent/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":250},"data":{"label":"Analysis Request"}},{"id":"agent_prep","type":"agent","position":{"x":340,"y":230},"data":{"label":"Data Prep (Local)","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You prepare data for analysis. Clean, format, and structure the input for downstream ML and NLP processing.","temperature":0.5,"maxTokens":4000}},{"id":"a2a_ml","type":"a2a-agent","position":{"x":680,"y":120},"data":{"label":"ML Analysis (Remote)","endpoint":"http://ml-service:9000","timeout":600,"agentName":"ML Analyzer"}},{"id":"a2a_nlp","type":"a2a-agent","position":{"x":680,"y":360},"data":{"label":"NLP Processing (Remote)","endpoint":"http://nlp-service:9000","timeout":300,"agentName":"NLP Processor"}},{"id":"agent_report","type":"agent","position":{"x":1020,"y":240},"data":{"label":"Report Synthesizer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You synthesize ML analysis and NLP processing results into clear, actionable reports with data-driven recommendations.","temperature":0.7,"maxTokens":8000,"otelEnabled":true,"otelServiceName":"report-agent"}},{"id":"output_1","type":"output","position":{"x":1320,"y":260},"data":{"label":"Analysis Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_prep","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_prep","target":"a2a_ml","sourceHandle":"output","targetHandle":"input"},{"id":"e3","source":"agent_prep","target":"a2a_nlp","sourceHandle":"output","targetHandle":"input"},{"id":"e4","source":"a2a_ml","target":"agent_report","sourceHandle":"output","targetHandle":"user-input"},{"id":"e5","source":"a2a_nlp","target":"agent_report","sourceHandle":"output","targetHandle":"user-input"},{"id":"e6","source":"agent_report","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}'),

-- Template 7: MCP-Powered Research Agent
('mcp-research-agent', 'MCP-Powered Research Agent', 'Agent connected to MCP servers for web search, file access, and knowledge retrieval. Demonstrates MCP integration with multiple transport types.', 'single-agent', NULL, 'intermediate', '["mcp", "research", "web-search", "knowledge-base", "tools"]', 'https://strandsagents.com/docs/user-guide/concepts/tools/mcp-tools/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":220},"data":{"label":"Research Query"}},{"id":"agent_1","type":"agent","position":{"x":420,"y":200},"data":{"label":"Research Agent","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a thorough research agent. Use available tools to search the web, read files, and query knowledge bases. Always provide sources and verify information from multiple angles.","temperature":0.7,"maxTokens":8000,"streaming":true,"otelEnabled":true}},{"id":"mcp_search","type":"mcp-tool","position":{"x":420,"y":40},"data":{"label":"Web Search MCP","serverName":"web_search","transportType":"stdio","command":"uvx","args":["web-search-mcp@latest"],"argsText":"web-search-mcp@latest","timeout":30}},{"id":"mcp_kb","type":"mcp-tool","position":{"x":660,"y":40},"data":{"label":"Knowledge Base MCP","serverName":"knowledge_base","transportType":"stdio","command":"uvx","args":["kb-mcp-server@latest"],"argsText":"kb-mcp-server@latest","timeout":30}},{"id":"tool_file","type":"tool","position":{"x":200,"y":40},"data":{"label":"File Reader","toolType":"built-in","toolName":"file_read"}},{"id":"output_1","type":"output","position":{"x":740,"y":220},"data":{"label":"Research Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"mcp_search","target":"agent_1","sourceHandle":"mcp-tools","targetHandle":"tools"},{"id":"e3","source":"mcp_kb","target":"agent_1","sourceHandle":"mcp-tools","targetHandle":"tools"},{"id":"e4","source":"tool_file","target":"agent_1","sourceHandle":"tool-output","targetHandle":"tools"},{"id":"e5","source":"agent_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 8: Workflow Task Pipeline (DAG)
('workflow-data-pipeline', 'Data Analysis Workflow (Task DAG)', 'DAG-based workflow with task dependencies and parallel execution. Tasks have system prompts, priorities, and explicit dependency chains. Independent tasks run in parallel.', 'workflow', NULL, 'intermediate', '["workflow", "DAG", "pipeline", "parallel", "dependencies", "tasks"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/workflow/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":60,"y":200},"data":{"label":"Data Source"}},{"id":"workflow_1","type":"workflow","position":{"x":380,"y":140},"data":{"label":"Analysis Pipeline","workflowId":"data_analysis_v2","tasks":[{"taskId":"extraction","description":"Extract key financial metrics and data points from the source","systemPrompt":"You extract and structure financial data from reports accurately.","dependencies":[],"priority":5},{"taskId":"trend_analysis","description":"Identify trends and patterns in the extracted data vs historical benchmarks","systemPrompt":"You identify statistical trends in financial time series data.","dependencies":["extraction"],"priority":4},{"taskId":"risk_assessment","description":"Assess potential risks based on trend deviations and market conditions","systemPrompt":"You evaluate financial risks using quantitative and qualitative factors.","dependencies":["extraction"],"priority":4},{"taskId":"report","description":"Generate comprehensive analysis report combining trends and risk assessment","systemPrompt":"You create clear, actionable financial analysis reports for executives.","dependencies":["trend_analysis","risk_assessment"],"priority":2}]}},{"id":"output_1","type":"output","position":{"x":720,"y":200},"data":{"label":"Analysis Report"}}],"edges":[{"id":"e1","source":"input_1","target":"workflow_1","sourceHandle":"output","targetHandle":"input"},{"id":"e2","source":"workflow_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}');
